using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using ResearchAgent;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI container ---
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// --- Tools ---
var notepad = new NotepadTool();
var webSearch = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the web_search tool to find relevant information (perform 2-3 searches with varied queries).
        2. As you discover key facts, use the add_note tool to record each important finding.
        3. After researching, use get_notes to review everything you recorded.
        4. Finally, write a concise summary that synthesizes all your findings.
        Be thorough but focused. Cite the sources from your search results.
        """,
    tools: tools,
    loggerFactory: loggerFactory);

// --- Run ---
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();

Console.Write("\nEnter a research topic (or press Enter for default): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    topic = "Recent breakthroughs in quantum computing 2025-2026";
}

Console.ForegroundColor = ConsoleColor.Yellow;
Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.ResetColor();

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research this topic thoroughly and provide a summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// --- Print collected notes ---
var notes = notepad.GetNotes();
if (!string.IsNullOrWhiteSpace(notes))
{
    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine("\n📝 Research Notes Collected:");
    Console.WriteLine(new string('─', 50));
    Console.ResetColor();
    Console.WriteLine(notes);
}

Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("\n✅ Research complete.");
Console.ResetColor();

