using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability to the research agent.
/// Uses the DuckDuckGo HTML search page (no API key required).
/// </summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for information on a given query. Returns a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            var request = new HttpRequestMessage(HttpMethod.Get, url);
            var response = await s_httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var results = ParseSearchResults(html);

            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"");
            sb.AppendLine();

            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"**{title}**");
                sb.AppendLine($"  {snippet}");
                sb.AppendLine($"  Source: {link}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Parse DuckDuckGo HTML results
        var resultPattern = new Regex(
            @"<a[^>]*class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>.*?<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        foreach (Match match in resultPattern.Matches(html))
        {
            var url = WebUtility.HtmlDecode(match.Groups[1].Value.Trim());
            var title = StripHtml(match.Groups[2].Value);
            var snippet = StripHtml(match.Groups[3].Value);

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            if (url.Contains("uddg="))
            {
                var uddgMatch = Regex.Match(url, @"uddg=([^&]+)");
                if (uddgMatch.Success)
                {
                    url = Uri.UnescapeDataString(uddgMatch.Groups[1].Value);
                }
            }

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add((title, snippet, url));
            }
        }

        return results;
    }

    private static string StripHtml(string input)
    {
        var text = Regex.Replace(input, @"<[^>]+>", "");
        return WebUtility.HtmlDecode(text).Trim();
    }
}

