using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capability so the agent can record findings during research.
/// </summary>
public sealed class NotepadTool
{
    private readonly List<string> _notes = [];
    private readonly object _lock = new();

    [Description("Add a research note. Use this to record key findings, facts, or insights discovered during research.")]
    public string AddNote(
        [Description("The note content to record")] string note)
    {
        lock (_lock)
        {
            _notes.Add(note);
        }

        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  📝 Note #{_notes.Count}: {Truncate(note, 80)}");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all research notes collected so far. Returns all saved notes numbered sequentially.")]
    public string GetNotes()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
            {
                return "No notes recorded yet.";
            }

            var sb = new StringBuilder();
            for (var i = 0; i < _notes.Count; i++)
            {
                sb.AppendLine($"[{i + 1}] {_notes[i]}");
            }

            return sb.ToString();
        }
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength - 3), "...");
}

